{
  "sentences": [
    {
      "text": "公寓在學校的旁邊。",
      "pinyin": "Gōngyù zài xuéxiào de pángbiān.",
      "pinyin_numeric": "gong1yu4 zai4 xue2xiao4 de5 pang2bian1.",
      "translation_en": "The apartment is next to the school.",
      "translation_ko": "아파트는 학교 옆에 있습니다."
    },
    {
      "text": "客廳在廚房的左邊。",
      "pinyin": "Kètīng zài chúfáng de zuǒbiān.",
      "pinyin_numeric": "ke4ting1 zai4 chu2fang2 de5 zuo3bian1.",
      "translation_en": "The living room is to the left of the kitchen.",
      "translation_ko": "거실은 주방 왼쪽에 있습니다."
    },
    {
      "text": "浴室在房間的裡面。",
      "pinyin": "Yùshì zài fángjiān de lǐmiàn.",
      "pinyin_numeric": "yu4shi4 zai4 fang2jian1 de5 li3mian4.",
      "translation_en": "The bathroom is inside the room.",
      "translation_ko": "욕실은 방 안에 있습니다."
    },
    {
      "text": "陽台在客廳的外面。",
      "pinyin": "Yángtái zài kètīng de wàimiàn.",
      "pinyin_numeric": "yang2tai2 zai4 ke4ting1 de5 wai4mian4.",
      "translation_en": "The balcony is outside the living room.",
      "translation_ko": "발코니는 거실 밖에 있습니다."
    },
    {
      "text": "廚房在公寓的後面。",
      "pinyin": "Chúfáng zài gōngyù de hòumiàn.",
      "pinyin_numeric": "chu2fang2 zai4 gong1yu4 de5 hou4mian4.",
      "translation_en": "The kitchen is at the back of the apartment.",
      "translation_ko": "주방은 아파트 뒤쪽에 있습니다."
    },
    {
      "text": "冰箱在廚房的水槽旁邊。",
      "pinyin": "Bīngxiāng zài chúfáng de shuǐcáo pángbiān.",
      "pinyin_numeric": "bing1xiang1 zai4 chu2fang2 de5 shui3cao2 pang2bian1.",
      "translation_en": "The refrigerator is next to the kitchen sink.",
      "translation_ko": "냉장고는 주방 싱크대 옆에 있습니다."
    },
    {
      "text": "洗衣機在浴室的門前面。",
      "pinyin": "Xǐyījī zài yùshì de mén qiánmiàn.",
      "pinyin_numeric": "xi3yi1ji1 zai4 yu4shi4 de5 men2 qian2mian4.",
      "translation_en": "The washing machine is in front of the bathroom door.",
      "translation_ko": "세탁기는 욕실 문 앞에 있습니다."
    },
    {
      "text": "床在房間的窗戶旁邊。",
      "pinyin": "Chuáng zài fángjiān de chuānghù pángbiān.",
      "pinyin_numeric": "chuang2 zai4 fang2jian1 de5 chuang1hu4 pang2bian1.",
      "translation_en": "The bed is next to the window in the room.",
      "translation_ko": "침대는 방의 창문 옆에 있습니다."
    },
    {
      "text": "書桌在衣櫃的右邊。",
      "pinyin": "Shūzhuō zài yīguì de yòubiān.",
      "pinyin_numeric": "shu1zhuo1 zai4 yi1gui4 de5 you4bian1.",
      "translation_en": "The desk is to the right of the wardrobe.",
      "translation_ko": "책상은 옷장 오른쪽에 있습니다."
    },
    {
      "text": "電視在客廳的沙發前面。",
      "pinyin": "Diànshì zài kètīng de shāfā qiánmiàn.",
      "pinyin_numeric": "dian4shi4 zai4 ke4ting1 de5 sha1fa1 qian2mian4.",
      "translation_en": "The TV is in front of the sofa in the living room.",
      "translation_ko": "텔레비전은 거실 소파 앞에 있습니다."
    }
  ]
}
